// ThreadResumeParams There are three ways to resume a thread: 1. By thread_id: load the thread from disk by thread_id and resume it. 2. By history: instantiate the thread from memory and resume it. 3. By path: load the thread from disk by path and resume it. The precedence is: history > path > thread_id. If using history or path, the thread_id param will be ignored. Prefer using thread_id whenever possible.
type ThreadResumeParams struct {
	ApprovalPolicy        *AskForApproval        `json:"approvalPolicy,omitempty"`
	BaseInstructions      *string                `json:"baseInstructions,omitempty"`
	Config                map[string]interface{} `json:"config,omitempty"`
	Cwd                   *string                `json:"cwd,omitempty"`
	DeveloperInstructions *string                `json:"developerInstructions,omitempty"`
	// Configuration overrides for the resumed thread, if any.
	Model         *string      `json:"model,omitempty"`
	ModelProvider *string      `json:"modelProvider,omitempty"`
	Personality   *Personality `json:"personality,omitempty"`
	Sandbox       *SandboxMode `json:"sandbox,omitempty"`
	ServiceTier   *ServiceTier `json:"serviceTier,omitempty"`
	ThreadID      string       `json:"threadId"`
}

type ThreadResumeResponse struct {
	ApprovalPolicy  AskForApproval   `json:"approvalPolicy"`
	Cwd             string           `json:"cwd"`
	Model           string           `json:"model"`
	ModelProvider   string           `json:"modelProvider"`
	ReasoningEffort *ReasoningEffort `json:"reasoningEffort,omitempty"`
	Sandbox         SandboxPolicy    `json:"sandbox"`
	ServiceTier     *ServiceTier     `json:"serviceTier,omitempty"`
	Thread          Thread           `json:"thread"`
}

type ThreadRollbackParams struct {
	// The number of turns to drop from the end of the thread. Must be >= 1. This only modifies the thread's history and does not revert local file changes that have been made by the agent. Clients are responsible for reverting these changes.
	NumTurns int64  `json:"numTurns"`
	ThreadID string `json:"threadId"`
}

type ThreadRollbackResponse struct {
	// The updated thread after applying the rollback, with `turns` populated. The ThreadItems stored in each Turn are lossy since we explicitly do not persist all agent interactions, such as command executions. This is the same behavior as `thread/resume`.
	Thread json.RawMessage `json:"thread"`
}

